import { useParams } from "react-router-dom";
import { useEffect, useState } from "react";

export default function IncidentDetail() {
  const { id } = useParams();
  const [incident, setIncident] = useState(null);
  const [form, setForm] = useState({});
  const [msg, setMsg] = useState("");

  // fetch incident
  useEffect(() => {
    fetch("http://localhost:8000/incidents")
      .then(res => res.json())
      .then(data => {
        const found = data.find(i => i.id === parseInt(id));
        setIncident(found);
      });
  }, [id]);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const res = await fetch(`http://localhost:8000/close/${id}`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(form)
    });

    const data = await res.json();
    setMsg(data.message || data.error);
  };

  if (!incident) return <p>Loading...</p>;

  return (
    <div style={{ padding: "20px" }}>
      <h2>🔍 Incident #{id}</h2>

      {/* DETAILS */}
      <div style={card}>
        <p><b>Component:</b> {incident.component_id}</p>
        <p><b>Status:</b> {incident.status}</p>
        <p><b>Signals:</b> {incident.signal_count}</p>
      </div>

      {/* FORM */}
      {incident.status === "OPEN" && (
        <form onSubmit={handleSubmit} style={card}>
          <input type="datetime-local" name="start" onChange={handleChange} required />
          <input type="datetime-local" name="end" onChange={handleChange} required />
          <input name="rootCause" placeholder="Root Cause" onChange={handleChange} />
          <input name="fix" placeholder="Fix" onChange={handleChange} />
          <input name="prevention" placeholder="Prevention" onChange={handleChange} />
          <button type="submit">Close Incident</button>
        </form>
      )}

      {msg && <p>{msg}</p>}
    </div>
  );
}

const card = {
  background: "#fff",
  padding: "15px",
  marginBottom: "15px",
  borderRadius: "10px",
  boxShadow: "0 2px 6px rgba(0,0,0,0.1)"
};
